import sys
input = sys.stdin.readline

def solve(n, m):
    if n > m:
        return 0
    L = max(n, m).bit_length()
    best = None
    # find min (n^r) for r > m
    # greedy bit by bit
    def go(bit, r_cur, tight, free):
        nonlocal best
        if bit < 0:
            if free or r_cur > m:
                v = n ^ r_cur
                if best is None or v < best:
                    best = v
            return
        nb = (n >> bit) & 1
        mb = (m >> bit) & 1
        for rb in [nb, 1-nb]:
            if tight and not free:
                if rb < mb:
                    continue
                go(bit-1, r_cur|(rb<<bit), tight and (rb==mb), rb>mb)
            else:
                go(bit-1, r_cur|(rb<<bit), False, True)
    go(L, 0, True, False)
    return best

t = int(input())
out = []
for _ in range(t):
    n, m = map(int, input().split())
    out.append(solve(n, m))
print('\n'.join(map(str, out)))

